// // This module shifts data to the left on each clock cycle and loads new data when the LOAD signal is low.
module shift_register(CLK, RST, LOAD, D, Q);
input CLK, RST, LOAD;
input [3:0] D;
output reg [3:0] Q;

always @(posedge CLK or posedge RST) begin
    if (RST)
        Q <= 0;
    else if (LOAD)
        Q <= D;
    else
        Q <= Q >> 1;
end

endmodule
